import { execution } from '@dynatrace-sdk/automation-utils';
export default async function ({ execution_id }) {
  const result = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/wait-for-completion/result`).then(r => r.json());
  if (result.AutomationExecutionStatus !== "Success") throw new Error("Instance launch failed!");
  console.log(`Launched instances: ${JSON.stringify(result)}`);
  return result;
}
